"use strict";(globalThis.webpackChunkship_it_book=globalThis.webpackChunkship_it_book||[]).push([[542],{5732(e,t,o){o.r(t),o.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>u,frontMatter:()=>a,metadata:()=>i,toc:()=>h});const i=JSON.parse('{"id":"part-1-builder-mindset/chapter-1-1-why-developers-dont-ship","title":"Chapter 1.1 \u2014 Why Developers Don\'t Ship","description":"The real reasons you haven\'t launched anything.","source":"@site/docs/part-1-builder-mindset/chapter-1-1-why-developers-dont-ship.mdx","sourceDirName":"part-1-builder-mindset","slug":"/part-1-builder-mindset/chapter-1-1-why-developers-dont-ship","permalink":"/ship-it-book/part-1-builder-mindset/chapter-1-1-why-developers-dont-ship","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Chapter 1.1 \u2014 Why Developers Don\'t Ship","description":"The real reasons you haven\'t launched anything.","sidebar_label":"1.1 \u2014 Why Developers Don\'t Ship"},"sidebar":"book","previous":{"title":"Part 1 \u2014 The Builder Mindset","permalink":"/ship-it-book/part-1-builder-mindset/"},"next":{"title":"1.2 \u2014 Builder vs Executor Trap","permalink":"/ship-it-book/part-1-builder-mindset/chapter-1-2-builder-vs-executor-trap"}}');var n=o(4848),r=o(8453);const a={title:"Chapter 1.1 \u2014 Why Developers Don't Ship",description:"The real reasons you haven't launched anything.",sidebar_label:"1.1 \u2014 Why Developers Don't Ship"},s="Why Developers Don't Ship",l={},h=[{value:"The Tutorial Trap",id:"the-tutorial-trap",level:2},{value:"The Perfectionism Trap",id:"the-perfectionism-trap",level:2},{value:"The Visibility Trap",id:"the-visibility-trap",level:2},{value:"The Lone Wolf Trap",id:"the-lone-wolf-trap",level:2},{value:"The Real Reason",id:"the-real-reason",level:2},{value:"The Numbers Don&#39;t Lie: Side Project Completion Rates",id:"the-numbers-dont-lie-side-project-completion-rates",level:2},{value:"The Dopamine Loop: Tutorials vs Real Building",id:"the-dopamine-loop-tutorials-vs-real-building",level:2},{value:"Two Developers: A Tale of Ship vs. Sideline",id:"two-developers-a-tale-of-ship-vs-sideline",level:2},{value:"The Opportunity Cost of Not Shipping",id:"the-opportunity-cost-of-not-shipping",level:2},{value:"How to Break the Cycle",id:"how-to-break-the-cycle",level:2},{value:"The Hard Truth",id:"the-hard-truth",level:2},{value:"Your Turn",id:"your-turn",level:2},{value:"What You Learned",id:"what-you-learned",level:2}];function d(e){const t={code:"code",h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"why-developers-dont-ship",children:"Why Developers Don't Ship"})}),"\n",(0,n.jsx)(t.p,{children:"You have a GitHub profile full of half-finished projects. A dozen domains you bought and never used. A Notes app with twenty startup ideas you'll never start. You're not alone. Most developers die with their best products still in their head."}),"\n",(0,n.jsx)(t.h2,{id:"the-tutorial-trap",children:"The Tutorial Trap"}),"\n",(0,n.jsx)(t.p,{children:"You've been learning for years. You finished a React course. You built a Todo app. You followed a tutorial for a Twitter clone, then another for an e-commerce store. You learned how to replicate what already exists. You never learned how to ship something original."}),"\n",(0,n.jsx)(t.p,{children:"Tutorials give you the feeling of progress without the risk of building. Every time you complete one, your brain releases the same dopamine it would if you'd built something real. But you didn't. You followed instructions. Instructions are not building."}),"\n",(0,n.jsx)(t.p,{children:"The hard truth: tutorials are crack for builders. They make you feel productive while keeping you trapped in a loop of consumption disguised as creation."}),"\n",(0,n.jsx)(t.h2,{id:"the-perfectionism-trap",children:"The Perfectionism Trap"}),"\n",(0,n.jsx)(t.p,{children:"You tell yourself your project isn't ready. The UI needs polish. You should refactor the backend. You need to add tests. You need to handle edge cases. You need a better database schema."}),"\n",(0,n.jsx)(t.p,{children:"So you rewrite the same project three times. Each time you learn a new framework, you start over. Each time you discover a better pattern, you migrate your codebase. Your project becomes a learning exercise disguised as a product."}),"\n",(0,n.jsx)(t.p,{children:"The real problem isn't the quality of your code. It's that you're building for yourself. You're the only user. And you're the harshest critic. You'll never satisfy yourself because you keep moving the goalpost."}),"\n",(0,n.jsx)(t.h2,{id:"the-visibility-trap",children:"The Visibility Trap"}),"\n",(0,n.jsx)(t.p,{children:"What if you ship and nobody cares?"}),"\n",(0,n.jsx)(t.p,{children:"This fear stops more developers than any technical challenge. You've spent months building something. You launch it. Three people visit the landing page. Your mom is one of them. Your best friend is another. The third one is you, refreshing the analytics dashboard."}),"\n",(0,n.jsx)(t.p,{children:"So you decide to wait until it's bigger. Better. More impressive. You'll launch when you have a million users lined up. You'll launch when TechCrunch writes about you. You'll launch when it's perfect."}),"\n",(0,n.jsx)(t.p,{children:"But perfect doesn't exist. And the longer you wait, the more likely you are to never launch at all."}),"\n",(0,n.jsx)(t.h2,{id:"the-lone-wolf-trap",children:"The Lone Wolf Trap"}),"\n",(0,n.jsx)(t.p,{children:"You build alone. No one sees your progress. No one holds you accountable. No one tells you when an idea is bad. No one pushes you to finish."}),"\n",(0,n.jsx)(t.p,{children:'When you work in isolation, every problem feels bigger than it is. A CSS bug becomes "maybe I should just give up." A deployment failure becomes "maybe this product wasn\'t meant to be." You have no one to tell you this is normal. That every shipper goes through this. That the only way out is through.'}),"\n",(0,n.jsx)(t.h2,{id:"the-real-reason",children:"The Real Reason"}),"\n",(0,n.jsx)(t.p,{children:"Here's what nobody tells you: shipping is not a technical skill. It's an emotional skill."}),"\n",(0,n.jsx)(t.p,{children:"You know enough to build your product. You have the technical ability. What you lack is the psychological tolerance for imperfection, criticism, and obscurity."}),"\n",(0,n.jsx)(t.p,{children:"Shipping means putting a piece of yourself into the world and accepting that the world might ignore it. That's terrifying. So you find comfort in another tutorial, another rewrite, another \"I'll start tomorrow.\""}),"\n",(0,n.jsx)(t.h2,{id:"the-numbers-dont-lie-side-project-completion-rates",children:"The Numbers Don't Lie: Side Project Completion Rates"}),"\n",(0,n.jsx)(t.p,{children:"Let's talk about the data, because you're not alone in this \u2014 you're the majority."}),"\n",(0,n.jsx)(t.p,{children:'A 2023 survey by Stack Overflow found that over 60% of developers have personal side projects. But independent research into side project completion rates tells a grimmer story. Studies on personal software projects estimate that fewer than 10% ever reach a "launched" state. Some estimates put the number as low as 3-5%. That means for every hundred developers who start a project, ninety-five never show it to another human being.'}),"\n",(0,n.jsx)(t.p,{children:'A study published in the Journal of Systems and Software (2021) found that personal software projects fail primarily due to "loss of motivation" (cited by 42% of respondents) and "scope creep" (cited by 31%). Only 8% failed for technical reasons. Your code works. Your motivation doesn\'t.'}),"\n",(0,n.jsx)(t.p,{children:"Think about that. Your next failure won't be because your code broke. It'll be because you broke."}),"\n",(0,n.jsx)(t.p,{children:"The startup world mirrors this. CB Insights analyzed over 100 startup post-mortems and found that 42% failed because there was no market need. But here's the part that doesn't get talked about: many of those founders never launched in the first place. They iterated in private, talked to friends, built features nobody asked for, and ran out of time and money before a single real user touched the product."}),"\n",(0,n.jsx)(t.p,{children:"If you're building in secret, you're building in a vacuum. And vacuums kill products."}),"\n",(0,n.jsx)(t.h2,{id:"the-dopamine-loop-tutorials-vs-real-building",children:"The Dopamine Loop: Tutorials vs Real Building"}),"\n",(0,n.jsx)(t.p,{children:"There's a neurological reason you reach for a tutorial instead of your own project, and it's not laziness."}),"\n",(0,n.jsx)(t.p,{children:"When you follow a tutorial, every step produces a visible result. You write code, you see output. You finish a section, you get a checkmark. Your brain releases dopamine in predictable bursts. The reward cycle is tight: action \u2192 result \u2192 satisfaction, in seconds or minutes."}),"\n",(0,n.jsx)(t.p,{children:"Real building doesn't work that way."}),"\n",(0,n.jsx)(t.p,{children:"When you build something original, you spend hours stuck on problems nobody has solved for you. You hit bugs that Stack Overflow hasn't seen. You make decisions without knowing if they're right. The reward cycle is loose: action \u2192 confusion \u2192 more action \u2192 doubt \u2192 breakthrough \u2192 relief \u2014 and that breakthrough might take days or weeks."}),"\n",(0,n.jsx)(t.p,{children:"Your brain is wired to prefer the tight loop. It's not a character flaw. It's biology. Your brain is optimizing for immediate reward, and shipping requires delayed gratification."}),"\n",(0,n.jsx)(t.p,{children:"Here's a concrete example. Say you want to build a habit tracker."}),"\n",(0,n.jsx)(t.p,{children:'The tutorial path: You search "build a habit tracker with Next.js." You find a YouTube series. You follow along. Five hours later, you have a functioning habit tracker with authentication, a database, and a dark mode toggle. You feel like a god.'}),"\n",(0,n.jsx)(t.p,{children:"The real path: You open a blank directory. You write a single HTML page with a checkbox and a counter. It's ugly. It doesn't persist data. But it works. You show it to a friend. They say \"I want to track habits by week, not by day.\" You realize your design is wrong. You rewrite it. You show it to five more people. Each time, you learn something you could never have learned from a tutorial."}),"\n",(0,n.jsx)(t.p,{children:"The tutorial gives you a finished product. The real path gives you a finished product that people actually want. Those are not the same thing."}),"\n",(0,n.jsx)(t.p,{children:"The difference is that on the real path, you shipped when the product was embarrassing. You got feedback when it was cheap to change. You iterated with real users, not with your imagination of what users want."}),"\n",(0,n.jsx)(t.h2,{id:"two-developers-a-tale-of-ship-vs-sideline",children:"Two Developers: A Tale of Ship vs. Sideline"}),"\n",(0,n.jsx)(t.p,{children:"Let me tell you about two developers I've known. I'll call them Alex and Jordan. Both were mid-level engineers at the same company. Both wanted to build a SaaS product. Both had similar skill levels."}),"\n",(0,n.jsx)(t.p,{children:"Alex spent six months building a project management tool. Alex refactored the codebase three times: first in Express, then in Fastify, then in NestJS. Alex spent two weeks designing a perfect color palette. Alex waited until the test suite had 90% coverage. Alex launched on a Tuesday at 3 PM. Zero users signed up. Alex blamed the market and started a new project."}),"\n",(0,n.jsx)(t.p,{children:'Jordan wanted to build a tool for freelancers to track invoices. Jordan spent one weekend building the ugliest possible version: a single HTML page with hardcoded data, no authentication, no database. Jordan posted it on Reddit with the title "I built this in a weekend, thoughts?" One hundred people tried it. Forty-three emailed Jordan asking for features. Jordan spent the next month building exactly what those forty-three people asked for. No refactoring. No perfect palette. Just features people had literally begged for.'}),"\n",(0,n.jsx)(t.p,{children:"Six months later, Jordan's tool had 2,000 paying users and a waitlist. Jordan quit the day job. Alex was still refactoring project number four."}),"\n",(0,n.jsx)(t.p,{children:'What was the difference? Technical skill? No. Jordan was a worse coder than Alex. The difference was that Jordan shipped when the product was bad, got real feedback, and iterated toward something people wanted. Alex shipped when the product was "ready" and discovered nobody cared.'}),"\n",(0,n.jsx)(t.p,{children:"Ship early. Ship ugly. Ship to learn."}),"\n",(0,n.jsx)(t.h2,{id:"the-opportunity-cost-of-not-shipping",children:"The Opportunity Cost of Not Shipping"}),"\n",(0,n.jsx)(t.p,{children:"Here's the math nobody does."}),"\n",(0,n.jsx)(t.p,{children:"Every year you don't ship, you're not just losing time. You're losing compounding learning. Every project you ship teaches you things you cannot learn any other way: how to talk to users, how to price a product, how to market, how to handle support, how to kill a feature that nobody uses."}),"\n",(0,n.jsx)(t.p,{children:"These skills compound. The developer who ships three terrible products in two years will be better at building products than the developer who spent two years perfecting one product that never launched. Not because they built more, but because they learned more cycles."}),"\n",(0,n.jsx)(t.p,{children:"There's also a financial cost. Indie developers who ship regularly build an audience over time. They write about their process. They share metrics. They build a reputation. That reputation leads to consulting gigs, job offers, acquisition offers, and investor interest."}),"\n",(0,n.jsx)(t.p,{children:"Consider the developer who ships one small tool per year for five years. Even if all five tools fail financially, that developer now has a portfolio, a mailing list, a network, and five cycles of real learning. They are worth ten times more as a founder than the developer who spent five years at a big company closing tickets."}),"\n",(0,n.jsx)(t.p,{children:"The market doesn't pay for potential. It pays for shipped products."}),"\n",(0,n.jsx)(t.h2,{id:"how-to-break-the-cycle",children:"How to Break the Cycle"}),"\n",(0,n.jsx)(t.p,{children:"You know the problem. You've read the data. Now here's the fix. It's not motivational. It's mechanical."}),"\n",(0,n.jsx)(t.p,{children:'Micro-commits are your first tool. Commit to shipping something so small that your brain can\'t argue with it. Not "build an MVP." Try "deploy a single HTML page to a public URL by Friday." Try "get one user to sign up for a mailing list." Try "post about your project on one forum."'}),"\n",(0,n.jsx)(t.p,{children:"The key is that the commitment is public, concrete, and time-bound. Tell someone you'll do it. Not your mom. Another builder. A coworker. A Twitter post. A public stake means the cost of quitting becomes visible."}),"\n",(0,n.jsx)(t.p,{children:"Public accountability works because it externalizes your internal stakes. When you're accountable only to yourself, you can quietly abandon a project at any time with zero consequences. Nobody knows. Nobody asks. But when you've told the world \"I'm launching a beta on Friday,\" backing out means admitting failure in public. Most people would rather ship something embarrassing than admit they gave up."}),"\n",(0,n.jsx)(t.p,{children:"The second tool is to reframe your definition of success. Stop measuring by users or revenue. Measure by learning. If you ship something and only three people use it but you learned something about your market, that's a win. You now know something you can't un-know. That knowledge is an asset that compounds into your next project."}),"\n",(0,n.jsx)(t.p,{children:'The third tool is to build in public. Start a blog. Tweet your progress. Write a weekly update. The people who follow your journey become your first users, your first critics, and your first advocates. Building in public also forces you to ship, because your audience expects updates. You won\'t want to write "I spent this week refactoring my database schema for the fourth time" because even you will realize how that sounds.'}),"\n",(0,n.jsx)(t.h2,{id:"the-hard-truth",children:"The Hard Truth"}),"\n",(0,n.jsx)(t.p,{children:"You will never feel ready. You will never feel like your product is complete. You will never feel confident that people will care."}),"\n",(0,n.jsx)(t.p,{children:"And that is exactly the right time to ship."}),"\n",(0,n.jsx)(t.p,{children:"The developers who ship are not more talented than you. They're not smarter. They're not better coders. They just decided that imperfect action beats perfect inaction. They accepted that their first version will embarrass them. And they launched anyway."}),"\n",(0,n.jsx)(t.p,{children:"The difference between a shipped product and an abandoned project is almost never about code quality, feature completeness, or technical innovation. It's about the willingness to be wrong in public."}),"\n",(0,n.jsx)(t.h2,{id:"your-turn",children:"Your Turn"}),"\n",(0,n.jsxs)(t.p,{children:["Open a terminal. Run ",(0,n.jsx)(t.code,{children:"ls"})," on your projects directory. Look at every project you started and never finished. Pick one. Any one."]}),"\n",(0,n.jsx)(t.p,{children:"Now answer three questions:"}),"\n",(0,n.jsxs)(t.ol,{children:["\n",(0,n.jsx)(t.li,{children:"What is the absolute smallest version of this that would work?"}),"\n",(0,n.jsx)(t.li,{children:"What one thing am I waiting for that I can decide to not wait for anymore?"}),"\n",(0,n.jsx)(t.li,{children:"Who is one person I can show this to this week?"}),"\n"]}),"\n",(0,n.jsx)(t.p,{children:"Write the answers down. Don't think. Just write."}),"\n",(0,n.jsx)(t.p,{children:'Then take it one step further. Set a public deadline. Post it somewhere. "I\'m shipping X on Friday." The smaller the commitment, the easier it is to keep. If you can\'t ship the whole thing, ship a landing page. Ship a screenshot. Ship a "this doesn\'t work yet" demo. Something is always better than nothing.'}),"\n",(0,n.jsx)(t.h2,{id:"what-you-learned",children:"What You Learned"}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsx)(t.li,{children:"Tutorials can be a form of procrastination disguised as learning"}),"\n",(0,n.jsx)(t.li,{children:"Perfectionism is fear of judgment, not a pursuit of quality"}),"\n",(0,n.jsx)(t.li,{children:"Building alone amplifies every obstacle"}),"\n",(0,n.jsx)(t.li,{children:"Shipping is an emotional skill, not a technical one"}),"\n",(0,n.jsx)(t.li,{children:"You will never feel ready \u2014 ship anyway"}),"\n",(0,n.jsx)(t.li,{children:"Fewer than 10% of side projects ever launch \u2014 most fail from motivation loss, not technical bugs"}),"\n",(0,n.jsx)(t.li,{children:"The brain prefers tutorial-style instant gratification; real building requires delayed gratification"}),"\n",(0,n.jsx)(t.li,{children:"Every year you don't ship is a year of compounding learning you forfeit"}),"\n",(0,n.jsx)(t.li,{children:"Micro-commits and public accountability break the inertia cycle"}),"\n"]})]})}function u(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>s});var i=o(6540);const n={},r=i.createContext(n);function a(e){const t=i.useContext(r);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:a(e.components),i.createElement(r.Provider,{value:t},e.children)}}}]);